+/// Create a bearer token interceptor that adds the token to outgoing requests.
+#[must_use]
+pub fn auth_bearer_interceptor(token: impl Into<String>) -> BearerAuthInterceptor {
+    BearerAuthInterceptor::new(token)
+}
