+/// Helper to extract ASCII string from metadata value.
+fn metadata_to_string(value: &MetadataValue) -> Option<&str> {
+    match value {
+        MetadataValue::Ascii(s) => Some(s.as_str()),
+        MetadataValue::Binary(_) => None,
+    }
+}
